import React from "react";

export default function Sidebar({ onNavigate }) {
  return (
    <div className="fixed top-[140px] left-0 flex flex-col items-center bg-[#88BCF8] w-[60px] py-[20px] px-[20px] gap-[28px] z-40 rounded-tr-[10px] rounded-br-[10px] shadow-md">
      {/* Trang chủ */}
      <img
        src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/ahb235du_expires_30_days.png"
        className="w-[30px] h-[30px] cursor-pointer hover:scale-110 transition"
        onClick={() => onNavigate("home")}
      />

      {/* Bạn bè */}
      <img
        src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/std8afed_expires_30_days.png"
        className="w-[30px] h-[30px] cursor-pointer hover:scale-110 transition"
        onClick={() => onNavigate("friends")}
      />

      {/* Thông báo */}
      <img
        src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/lr1rzg6o_expires_30_days.png"
        className="w-[30px] h-[30px] cursor-pointer hover:scale-110 transition"
        onClick={() => onNavigate("notifications")}
      />

            {/* 📰 NewFeed (Bảng tin) */}
      <img
        src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/gkanffrw_expires_30_days.png"
        className="w-[30px] h-[30px] cursor-pointer hover:scale-110 transition"
        onClick={() => onNavigate("newfeed")}
      />

      {/* profile*/}
      <img
        src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/8e81e38m_expires_30_days.png"
        className="w-[30px] h-[30px] cursor-pointer hover:scale-110 transition"
        onClick={() => onNavigate("profile")}
      />
      {/* setting*/}
      <img
        src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/vxprnu1g_expires_30_days.png"
        className="w-[30px] h-[30px] cursor-pointer hover:scale-110 transition"
        onClick={() => onNavigate("setting")}
      />
    </div>
  );
}
